var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"그로니아 수도권 상공\\n페가수스 수송기, <color=#ffd34c>메이즈 전대</color> 초계 임무 중\\nCSE Level <color=#ffd34c>1.3</color>","JPN":"グロニア首都圏上空\\nペガサス輸送機、<color=#ffd34c>メイズ戦隊</color>哨戒任務中\\nCSE Level <color=#ffd34c>1.3</color>","ENG":"[[","TWN":"格羅尼亞首都上空\\n天馬運輸機，<color=#ffd34c>梅茲戰隊</color> 執行巡邏任務中\\nCSE Level <color=#ffd34c>1.3</color>","THA":"ท่าอวกาศยานนครหลวงโกรเนีย\\nเครื่องบินขนส่งเพกาซัส<color=#ffd34c>กองพลเขาวงกต</color>กำลังลาดตระเวน\\nระดับ CSE <color=#ffd34c>1.3</color>","VTN":"Vùng trời Đô thị Gronia\\nMáy bay Vận tải Pegasus,<color=#ffd34c>Sư đoàn Mê cung</color>Tuần tra\\nCấp CSE<color=#ffd34c>1.3</color>","SCN":"格洛尼亚首都区域上空\\n天马运输机，<color=#ffd34c>梅兹战队</color>，正在执行巡逻任务\\nCSE等级<color=#ffd34c>1.3</color>","DEU":"[[","FRA":"Espace aérien de Gronia\\nAvion de transport Pegasus, <color=#ffd34c>Division Maze en patrouille</color>\\nNiveau d'ECM : <color=#ffd34c>1,3</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"현재 고도는 4천. 기체 상태는 양호하며 침식파 반응도 예상 범위 이내입니다.","JPN":"ただいま高度は4000。機体の状態は良好、侵食波反応も予想範囲内です。","ENG":"The current altitude is 4000. We’re fine on gas and the Corruption ray response is within the expected range.","TWN":"目前高度4千，機體狀況良好，侵蝕波反應也在預期範圍內。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"침식 현상의 일종이라지만, 정말 아름다운 하늘이네요. 가능하다면 오래 날고 싶어요.","JPN":"侵食現象の一種ですけど、本当に綺麗な空ですね。できれば長く飛びたいです。","ENG":"They say it’s part of the Counterside Effect, but my, what an absolutely beautiful sky. I hope we fly as long as we can.","TWN":"雖說是侵蝕現象的其中一種，但天空真的好美，可以的話，真希望可以飛久一點～"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그래. 남들 앞에서만 적당히 뻣뻣하게 굴어.","JPN":"そう。他の人の前では適度に堅苦しく行動してね。","ENG":"Yes. Just remember to act stiff when you’re around others.","TWN":"嗯嗯，在外人面前要收斂一點。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"지금 우리는 관리국에서 파견한 오피셜 서포트야. 수송기에 탑재된 AI가 감정이 풍부하면 다들 깜짝 놀랄걸.","JPN":"今の私たちは管理局から派遣されたオフィシャルサポート。輸送機に搭載されたAIが感情豊かだったらみんなビックリするわ。","ENG":"We are the Official Support dispatched from the Administration. If everyone sees an AI full of emotion, it would be a little too surprising for them.","TWN":"我們現在的角色可是管理局派來的官方支援，運輸機上搭載的AI如果情感太豐富，其他人會起疑的。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"하하, 검문 나온 병사들이 어디서 구한 장비냐고 물어볼 때는 정말 아찔했죠.","JPN":"はは、検問の兵士にどこで手に入れた装備なのかと聞かれた時には本当にヒヤっとしましたね。","ENG":"Ha ha, I drew cold sweat when the soldiers during the inspection asked where we got such hi-tech equipment.","TWN":"哈哈，那些士兵問我這些裝備是哪來的時候，真的嚇我一跳呢！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"난 그쪽 무장 상태가 더 아찔하더라.","JPN":"私はそっちの武装状態の方がもっとヒヤっとしたわよ。","ENG":"I found the state of their equipment to be more surprising honestly.","TWN":"我才被你的武裝狀態給嚇到呢！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"요즘 시대에 누가 그런 구식 무기로 무장시키니? 애들 위험하게.","JPN":"今時あんな旧型の武器で武装させるなんて有り得ないわよね？　子どもたちが危ないでしょ。","ENG":"They still use such old-fashioned weapons in this day and age. So dangerous.","TWN":"最近誰會用這種舊型武器？沒問題吧？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"저희가 동면해 있는 동안 계속 내전 상태였다니, 어쩔 수 없었겠죠.","JPN":"私たちが冬眠してる間ずっと内戦状態だったそうですから、仕方がなかったんでしょう。","ENG":"They were in a state of constant civil war while we were in cryostasis. I guess it couldn’t be helped.","TWN":"有什麼辦法，誰叫我們冬眠這段期間，一直是在內戰的狀態。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"그보다 이제 곧 초계 임무가 끝납니다. 오늘은 조금 푹 쉬십시오, 부전대장님.","JPN":"それよりもうすぐ哨戒任務も終わりです。今日はよくお休みください、副戦隊長。","ENG":"Anyways, the patrol mission will be over soon. Get some rest, Deputy Commander.","TWN":"不過巡邏任務就快結束了，副戰隊長，你今天就好好休息吧！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"응? 시간이 벌써 그렇게 됐나?","JPN":"うん？　もうそんな時間？","ENG":"Huh? It’s already that time of day?","TWN":"嗯？都已經是這個時間啦？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"난 됐어. 다른 애들이나 신경 써 줘.","JPN":"私は大丈夫。他の子どもたちを気にかけて。","ENG":"I’m fine, thank you. Look after the other ones.","TWN":"我沒關係，你去照顧其他孩子吧～"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"관리자님의 당부 때문에 그러십니까?","JPN":"管理者様からの要請のためですか？","ENG":"Are you doing this because of the Administrator’s request?","TWN":"是因為管理者的吩咐嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"글쎄……. 어떠려나.","JPN":"さあ……どうかしら。","ENG":"Well... What do you think?","TWN":"這個嘛……會怎麼樣呢？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"초계 임무?","JPN":"哨戒任務？","ENG":"The patrol mission?","TWN":"巡邏任務?"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};